update recipes set recipe_kind='cooked', instructions='{"reheat": "Reheat the beef in a pan or microwave before filling.", "storage": "Store the beef up to 3 days refrigerated; fill the lettuce fresh.", "sections": [{"steps": [{"n": 1, "temp": null, "text": "Dice the onion. Brown the ground beef with the onion in a little olive oil over medium-high, 6-7 minutes, breaking it up as it cooks.", "type": "cook", "active": false, "appliance": "stovetop", "duration_min": 7, "ingredient_refs": ["ground beef, 90% lean, raw", "onions, raw", "olive oil"]}, {"n": 2, "temp": null, "text": "Season with cumin and a pinch of salt and stir through.", "type": "prep", "active": true, "appliance": null, "duration_min": 1, "ingredient_refs": ["cumin, ground"]}], "title": "Cook the beef"}, {"steps": [{"n": 3, "temp": null, "text": "Spoon the beef into romaine leaves and top with sliced avocado and salsa.", "type": "assemble", "active": true, "appliance": null, "duration_min": 5, "ingredient_refs": ["romaine lettuce", "avocado, raw", "salsa, ready-to-serve"]}], "title": "Fill the wraps"}], "make_ahead": "Cook the beef up to 3 days ahead.", "cook_time_min": 8, "prep_time_min": 5, "total_time_min": 13, "yield_servings": 1}'::jsonb where id='13f32de3-da29-4481-be7c-21858195ebcd' and user_id is null;

