update recipes set recipe_kind='cooked', instructions='{"reheat": "Serve cold or gently warm the salmon.", "storage": "Store components separate; roll fresh so the tortilla stays firm.", "sections": [{"steps": [{"n": 1, "temp": null, "text": "Season the salmon and pan-sear in a little olive oil, about 4 minutes per side, until it flakes; flake into pieces.", "type": "cook", "active": false, "appliance": "stovetop", "duration_min": 10, "ingredient_refs": ["salmon, atlantic, farmed, raw", "olive oil"]}], "title": "Cook the salmon"}, {"steps": [{"n": 2, "temp": null, "text": "Whisk the lemon juice, dijon mustard, and a little olive oil into a quick Caesar-style dressing; toss with the chopped romaine and parmesan.", "type": "prep", "active": true, "appliance": null, "duration_min": 3, "ingredient_refs": ["lemon juice, raw", "dijon mustard", "olive oil", "romaine lettuce", "parmesan cheese"]}, {"n": 3, "temp": null, "text": "Pile the romaine and salmon onto the flour tortilla and roll up tightly.", "type": "assemble", "active": true, "appliance": null, "duration_min": 2, "ingredient_refs": ["flour tortilla, large", "salmon, atlantic, farmed, raw"]}], "title": "Build the wrap"}], "make_ahead": "Cook the salmon up to 2 days ahead.", "cook_time_min": 10, "prep_time_min": 5, "total_time_min": 15, "yield_servings": 1}'::jsonb where id='6f6c804a-5964-4339-8180-fbe28af551e1' and user_id is null;

